CREATE OR REPLACE FUNCTION clinlims.generate_tb_sample_id()
RETURNS VARCHAR(20) AS $$
DECLARE
    current_year VARCHAR(2);
    next_seq INTEGER;
    result VARCHAR(20);
BEGIN
    -- Get last two digits of current year
    current_year := TO_CHAR(CURRENT_DATE, 'YY');

    -- Get next sequence value
    next_seq := NEXTVAL('clinlims.tb_sample_id_seq');

    -- Format as NNN/YY (e.g., 001/25, 345/25)
    result := LPAD(next_seq::VARCHAR, 3, '0') || '/' || current_year;

    RETURN result;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION clinlims.reset_tb_sample_id_seq_if_new_year()
RETURNS VOID AS $$
DECLARE
    last_tb_id VARCHAR(20);
    last_year VARCHAR(2);
    current_year VARCHAR(2);
BEGIN
    -- Get the most recent TB sample ID
    SELECT tb_sample_id INTO last_tb_id
    FROM clinlims.sample_item
    WHERE tb_sample_id IS NOT NULL
    ORDER BY id DESC
    LIMIT 1;

    IF last_tb_id IS NOT NULL THEN
        -- Extract year from last ID (format: NNN/YY)
        last_year := SPLIT_PART(last_tb_id, '/', 2);
        current_year := TO_CHAR(CURRENT_DATE, 'YY');

        -- Reset sequence if year has changed
        IF last_year != current_year THEN
            PERFORM SETVAL('clinlims.tb_sample_id_seq', 1, false);
        END IF;
    END IF;
END;
$$ LANGUAGE plpgsql;
